code.lab.plugin.guide.fieldsMiniPitchSte:
type（必須）: "miniPitchSteps"
description（任意）: 説明テキスト { "ja": "...", "en": "..." }
cameraPosition（任意）: カメラ位置 [x, y, z]
steps（必須）: ステップの配列（1つ以上）
  各ステップ: { label: { "ja": "...", "en": "..." }, players: [...] }
  playersの形式はminiPitchDemoと同じ

code.lab.plugin.guide.controlTypesDesc:
buttonGroup: ボタン切替 { type: "buttonGroup", bind: "状態キー", options: [{ value: "値", label: { ja, en } }] }
textInput: テキスト入力 { type: "textInput", bind: "状態キー", label?: { ja, en }, maxLength?: 数値 }
numberInput: 数値入力 { type: "numberInput", bind: "状態キー", label?: { ja, en } }
toggle: ON/OFFトグル { type: "toggle", bind: "状態キー", label?: { ja, en } }
slider: スライダー { type: "slider", bind: "状態キー", label?: { ja, en } }
